# 3. HELPER FUNCTIONS TO CHECK POSITION TYPES
# ============================================
# Check if position has 'Q' at the start of third section
def has_q_start_udf(position):
    if position is None:
        return False
    parts = position.split('-')
    if len(parts) >= 3:
        third_part = parts[2]
        return third_part.startswith('Q')
    return False


# Check if position contains 'W' in third section
def has_w_udf(position):
    if position is None:
        return False
    parts = position.split('-')
    if len(parts) >= 3:
        third_part = parts[2]
        return 'W' in third_part
    return False

# Register UDFs
has_q_start = F.udf(has_q_start_udf, BooleanType())
has_w = F.udf(has_w_udf, BooleanType())
